+function resolveWindowsHomeParts(homeDir: string): { homeDrive?: string; homePath?: string } {
+  if (process.platform !== "win32") {
+    return {};
+  }
+  const match = homeDir.match(/^([A-Za-z]:)(.*)$/);
+  if (!match) {
+    return {};
+  }
+  return {
